const item = $input.first().json;
const body = item.body || item;
let isValidMessage = false;
let phone = '';
let name = 'Customer';
let text = '';
let messageType = '';

try {
  const entry = body.entry && body.entry[0];
  const change = entry && entry.changes && entry.changes[0];
  const value = change && change.value;
  const message = value && value.messages && value.messages[0];
  const contact = value && value.contacts && value.contacts[0];

  if (message) {
    isValidMessage = true;
    phone = message.from;
    name = (contact && contact.profile && contact.profile.name) || 'Customer';
    messageType = message.type;
    if (messageType === 'text') {
      text = (message.text.body || '').trim();
    } else if (messageType === 'button') {
      text = (message.button && message.button.text || '').trim();
    } else if (messageType === 'interactive') {
      text = (message.interactive && message.interactive.button_reply && message.interactive.button_reply.title) || '';
    } else {
      // unsupported type (image, audio, location, sticker etc.)
      text = '';
    }
  }
} catch (e) {
  isValidMessage = false;
}

return [{ json: { isValidMessage, phone, name, text, messageType } }];

const incoming = $('Parse Incoming Message').first().json;
const rows = $input.all();
let session;
if (rows.length === 0 || !rows[0].json || !rows[0].json.Phone) {
  session = { Phone: incoming.phone, Stage: 'NONE', Items: '', Total: '', Address: '', OrderID: '' };
} else {
  session = rows[0].json;
  if (!session.Stage) session.Stage = 'NONE';
}
return [{ json: { ...incoming, session } }];

// NOTE: adjust the timeZone below to your restaurant's local timezone.
const TIMEZONE = 'Asia/Karachi';
const ctx = $('Normalize Session').first().json;
const hoursRows = $input.all().map(i => i.json);

const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const now = new Date(new Date().toLocaleString('en-US', { timeZone: TIMEZONE }));
const currentDay = days[now.getDay()];
const currentTime = now.toTimeString().slice(0,5);

const todayRow = hoursRows.find(r => r.Day === currentDay) || {};
let isOpen = false;
if (String(todayRow.AcceptOrders || '').toLowerCase() === 'yes' && todayRow.Open && todayRow.Open !== 'Closed') {
  if (currentTime >= todayRow.Open && currentTime <= todayRow.Close) {
    isOpen = true;
  }
}

return [{ json: { ...ctx, isOpen, todayOpen: todayRow.Open || 'Closed', todayClose: todayRow.Close || 'Closed' } }];

