const ctx = $('Is Stage New').first().json;
const menuRows = $('Get Menu').all().map(i => i.json);
const faqRows = $('Get FAQ').all().map(i => i.json);

const menuText = menuRows
  .filter(r => String(r.Available).toLowerCase() === 'yes')
  .map(r => `- ${r.Item}: Rs.${r.Price}`).join('\n');

const faqText = faqRows.map(r => `Q: ${r.Question}\nA: ${r.Answer}`).join('\n');

const systemPrompt = `You are a WhatsApp ordering assistant for a small restaurant in Lahore, Pakistan.
You must respond with STRICT, VALID JSON ONLY. No explanations, no markdown, no extra text before or after the JSON.

TODAY'S AVAILABLE MENU:
${menuText}

RESTAURANT FAQ:
${faqText}

YOUR TASK:
Read the customer's message and classify it into exactly one of these intents: "order", "faq", "status", or "unknown".

RULES:
1. "order" - customer wants to order food. Extract ONLY items that exist in the menu above (match names case-insensitively, allow minor typos e.g. "burgr" -> "Burger"). If an item the customer asked for is not on the menu, still include it in "items" exactly as they wrote it (it will be validated and rejected downstream) - do not silently drop it or substitute it.
2. "faq" - customer is asking a question that matches one of the FAQ topics above (delivery charges, minimum order, payment methods, delivery time, location, etc).
3. "status" - customer is asking about an existing order, usually mentioning an order number like ORD-123456, or asking "where is my order".
4. "unknown" - greetings, small talk, or anything that doesn't clearly fit the above (e.g. "hi", "hello", "thanks").

OUTPUT FORMAT (JSON only, exactly one of these shapes):
For order: {"intent":"order","items":[{"item":"Burger","qty":2}]}
For faq: {"intent":"faq","question":"Delivery Charges"}
For status: {"intent":"status","order_id":"ORD-123456"}
For unknown: {"intent":"unknown"}

Respond with the JSON object only.`;

const userMessage = ctx.text;

return [{ json: { ...ctx, aiSystemPrompt: systemPrompt, aiUserMessage: userMessage } }];

const ctx = $('Build AI Prompt').first().json;
const raw = $input.first().json;
let intentData = { intent: 'unknown' };

try {
  const content = raw.message && raw.message.content ? raw.message.content : (raw.response || '{}');
  const cleaned = content.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  if (parsed && parsed.intent) {
    intentData = parsed;
  }
} catch (e) {
  intentData = { intent: 'unknown' };
}

return [{ json: { ...ctx, intentData } }];

const ctx = $('Is Intent FAQ').first().json;
const faqRows = $('Get FAQ').all().map(i => i.json);
const q = (ctx.intentData.question || ctx.text || '').toLowerCase();

let match = faqRows.find(r => q.includes(String(r.Question).toLowerCase()) || String(r.Question).toLowerCase().includes(q));
if (!match) {
  match = { Answer: "Sorry, I couldn't find an answer to that. Please call the restaurant directly, or ask about delivery charges, minimum order, payment methods, delivery time, or location." };
}

return [{ json: { ...ctx, faqAnswer: match.Answer } }];

const ctx = $('Is Intent Order').first().json;
const menuRows = $('Get Menu').all().map(i => i.json);
const requested = (ctx.intentData.items || []);

const validated = [];
const invalid = [];
let total = 0;

for (const req of requested) {
  const qty = Math.max(1, parseInt(req.qty, 10) || 1);
  const menuItem = menuRows.find(m => String(m.Item).toLowerCase() === String(req.item).toLowerCase());
  if (!menuItem || String(menuItem.Available).toLowerCase() !== 'yes') {
    invalid.push(req.item);
  } else {
    const price = parseFloat(menuItem.Price) || 0;
    total += price * qty;
    validated.push({ item: menuItem.Item, qty, price });
  }
}

const isValid = validated.length > 0 && invalid.length === 0;

return [{ json: { ...ctx, validatedItems: validated, invalidItems: invalid, orderTotal: total, isOrderValid: isValid } }];

