const ctx = $('Is Intent Status').first().json;
let orderId = ctx.intentData.order_id || '';
if (!orderId) {
  const m = ctx.text.match(/ORD-?\d+/i);
  orderId = m ? m[0].toUpperCase().replace('ORD', 'ORD-').replace('--', '-') : '';
}
return [{ json: { ...ctx, lookupOrderId: orderId } }];

const ctx = $('Extract Order ID').first().json;
const rows = $input.all();
let reply;
if (!ctx.lookupOrderId) {
  reply = "Please tell me your order number, e.g. \"status ORD-123456\".";
} else if (rows.length === 0 || !rows[0].json.OrderID) {
  reply = `Sorry, I couldn't find order ${ctx.lookupOrderId}. Please double check the order number.`;
} else {
  const o = rows[0].json;
  reply = `Order ${o.OrderID}\nStatus: ${o.Status}\nTotal: Rs.${o.Total}`;
}
return [{ json: { ...ctx, statusReply: reply } }];

const ctx = $('Is Stage Waiting Address').first().json;
const orderId = 'ORD-' + Date.now().toString().slice(-6);
const address = ctx.text;
return [{ json: { ...ctx, address, orderId } }];

