const ctx = $('Is Stage Waiting Confirmation').first().json;
const t = (ctx.text || '').toLowerCase();
let confirmationResult = 'UNCLEAR';
if (/\b(yes|y|confirm|ok|okay)\b/.test(t)) confirmationResult = 'YES';
else if (/\b(no|n|cancel)\b/.test(t)) confirmationResult = 'NO';
return [{ json: { ...ctx, confirmationResult } }];

